body:
Let's suppose I have a Flip-Flop with a gated clock....  I'm using the code below in an FPGA to reset my flip-flops... (this works in an FPGA synthesis compile because Flip-flops default to zero state when loading the FPGA image file...)  However, when I simulate the correct way using `define MODELSIM , then icarus verilog doesn't reset the flip-flop in my design that have a gated clock at the time of the reset, but modelsim does this correctly....

```
`timescale 1ns/10ps

`define MODELSIM
//`define IVERILOG

// Generate FPGA internal Reset after Bit image is loaded...
module zynq_pl_genrst(
    input  wire sys_clk,
    output wire sys_rstn
);

localparam W = 40;


// Works in modelsim but doesn't work in icarus verilog to reset asynchonous flip-flops.
`ifdef MODELSIM
    reg [W-1:0] d = {1'b0, {W-1{1'b0}}};
`endif

// Work around to fix Icarus Verilog to behave like modelsim...
`ifdef IVERILOG
    reg [W-1:0] d = {1'bX, {W-1{1'b0}}};
`endif


always @(posedge sys_clk) begin
        d[0]     <= 1'b1;
	d[W-1:1] <= d[W-2:0];
end

assign sys_rstn = d[W-1];

endmodule

```


example:

```
// Sorry, i don't have time to test this code... but this is basically my attempt to recreate what is happening in my simulation...
// and to show difference between icarus and modelsim...


module test;

reg clk;
wire rstn;
reg  [7:0] d;
reg  [7:0] q;

initial begin
    clk = 1'b0;
   forever begin
      #10 clk = 1'b0;
      #10 clk = 1'b1;
   end
end

zynq_pl_genrst genrst(
   sys_clk  (clk),
   sys_rstn (rstn)
);

dff dff1(
   .clk (1'b0),   //gated clock,  zero at time of reset.
   .arstn (arstn), // internally generated FPGA reset that goes high x cycles after FPGA configuration
   .d  (d),   //d should reset in icarus when `modelsim is defined, however, it remains an 'X'... modelsim does this correctly.
   .q (q)
);
endmodule

```

